#include "physics.h"
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <time.h>
#ifdef _OPENMP
#include <omp.h>
#endif

// Utility random double in [0,1)
static inline double urand(unsigned int *state) {
    // simple LCG to avoid global rand()
    *state = (*state * 1664525u + 1013904223u);
    return ((*state >> 8) & 0xFFFFFF) / (double)0x1000000;
}

void init_particles(Particle *p, int n, double size, unsigned int seed) {
    unsigned int st = seed;
    for (int i = 0; i < n; i++) {
        p[i].x = urand(&st) * size;
        p[i].y = urand(&st) * size;
        p[i].vx = 0.0;
        p[i].vy = 0.0;
    }
}

// Binning structure
typedef struct {
    int G;           // grid size (GxG)
    double bin_w;    // bin width
    int *counts;     // counts per bin
    int *offsets;    // offsets per bin
    int *indices;    // particle indices in bins (length n)
} Bins;

static void bins_init(Bins *b, double size, double cutoff, int n) {
    b->G = (int)ceil(size / cutoff);
    if (b->G < 2) b->G = 2;
    b->bin_w = size / b->G;
    size_t bins_n = (size_t)b->G * (size_t)b->G;
    b->counts  = (int*)calloc(bins_n, sizeof(int));
    b->offsets = (int*)calloc(bins_n, sizeof(int));
    b->indices = (int*)malloc((size_t)n * sizeof(int));
}

static void bins_free(Bins *b) {
    free(b->counts);
    free(b->offsets);
    free(b->indices);
}

static inline int bin_index(const Bins *b, double x, double y, double size) {
    int ix = (int)floor(x / b->bin_w);
    int iy = (int)floor(y / b->bin_w);
    if (ix < 0) ix = 0; if (ix >= b->G) ix = b->G - 1;
    if (iy < 0) iy = 0; if (iy >= b->G) iy = b->G - 1;
    return iy * b->G + ix;
}

static void bins_build(Bins *b, const Particle *p, int n, double size) {
    size_t bins_n = (size_t)b->G * (size_t)b->G;
    memset(b->counts, 0, bins_n * sizeof(int));
    // first pass count
    for (int i = 0; i < n; i++) {
        int bi = bin_index(b, p[i].x, p[i].y, size);
        b->counts[bi]++;
    }
    // exclusive prefix sum for offsets
    int sum = 0;
    for (size_t i = 0; i < bins_n; i++) {
        b->offsets[i] = sum;
        sum += b->counts[i];
        b->counts[i] = 0; // reuse as cursor
    }
    // second pass fill indices
    for (int i = 0; i < n; i++) {
        int bi = bin_index(b, p[i].x, p[i].y, size);
        int pos = b->offsets[bi] + b->counts[bi]++;
        b->indices[pos] = i;
    }
}

static inline void confine(Particle *q, double size) {
    // Reflecting boundaries
    if (q->x < 0) { q->x = -q->x; q->vx = -q->vx; }
    if (q->y < 0) { q->y = -q->y; q->vy = -q->vy; }
    if (q->x > size) { q->x = 2*size - q->x; q->vx = -q->vx; }
    if (q->y > size) { q->y = 2*size - q->y; q->vy = -q->vy; }
}

static void compute_forces(const Particle *p, int n, const SimParams *sp, const Bins *b, double *fx, double *fy) {
    const double cutoff2 = sp->cutoff * sp->cutoff;
    const double k = 5.0; // repulsion strength
    const double eps = 1e-12;
    // zero forces
    #pragma omp parallel for ifdef(_OPENMP)
    for (int i = 0; i < n; i++) { fx[i] = 0.0; fy[i] = 0.0; }
    // traverse particles and neighbor bins
    #ifdef _OPENMP
    #pragma omp parallel for schedule(static)
    #endif
    for (int i = 0; i < n; i++) {
        int bi = bin_index(b, p[i].x, p[i].y, sp->size);
        int bix = bi % b->G;
        int biy = bi / b->G;
        double fix = 0.0, fiy = 0.0;
        for (int dy = -1; dy <= 1; dy++) {
            for (int dx = -1; dx <= 1; dx++) {
                int nx = bix + dx;
                int ny = biy + dy;
                if (nx < 0 || ny < 0 || nx >= b->G || ny >= b->G) continue;
                int nbi = ny * b->G + nx;
                int start = b->offsets[nbi];
                int count = (nbi + 1 < b->G*b->G) ? (b->offsets[nbi+1] - start) : (n - start);
                // iterate indices in this neighbor bin
                for (int kidx = 0; kidx < count; kidx++) {
                    int j = b->indices[start + kidx];
                    if (j == i) continue;
                    double dxp = p[j].x - p[i].x;
                    double dyp = p[j].y - p[i].y;
                    double r2 = dxp*dxp + dyp*dyp;
                    if (r2 < cutoff2 && r2 > eps) {
                        double r = sqrt(r2);
                        double strength = k * (1.0 - (r / sp->cutoff));
                        double invr = 1.0 / r;
                        fix -= strength * dxp * invr; // repulsive
                        fiy -= strength * dyp * invr;
                    }
                }
            }
        }
        fx[i] = fix;
        fy[i] = fiy;
    }
}

static double walltime() {
    struct timespec ts; clock_gettime(CLOCK_MONOTONIC, &ts);
    return ts.tv_sec + ts.tv_nsec * 1e-9;
}

static double simulate_core(Particle *p, const SimParams *sp, int use_openmp, int threads) {
    if (use_openmp) {
        #ifdef _OPENMP
        if (threads > 0) omp_set_num_threads(threads);
        #endif
    }
    int n = sp->n;
    Bins bins; bins_init(&bins, sp->size, sp->cutoff, n);
    double *fx = (double*)malloc((size_t)n * sizeof(double));
    double *fy = (double*)malloc((size_t)n * sizeof(double));
    double t0 = walltime();
    for (int step = 0; step < sp->steps; step++) {
        bins_build(&bins, p, n, sp->size);
        compute_forces(p, n, sp, &bins, fx, fy);
        // integrate
        #ifdef _OPENMP
        if (use_openmp) {
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < n; i++) {
                p[i].vx = sp->damping * (p[i].vx + sp->dt * fx[i]);
                p[i].vy = sp->damping * (p[i].vy + sp->dt * fy[i]);
                p[i].x += sp->dt * p[i].vx;
                p[i].y += sp->dt * p[i].vy;
                confine(&p[i], sp->size);
            }
        } else
        #endif
        {
            for (int i = 0; i < n; i++) {
                p[i].vx = sp->damping * (p[i].vx + sp->dt * fx[i]);
                p[i].vy = sp->damping * (p[i].vy + sp->dt * fy[i]);
                p[i].x += sp->dt * p[i].vx;
                p[i].y += sp->dt * p[i].vy;
                confine(&p[i], sp->size);
            }
        }
    }
    double t1 = walltime();
    free(fx); free(fy); bins_free(&bins);
    return t1 - t0;
}

double simulate_serial(Particle *p, const SimParams *sp) {
    return simulate_core(p, sp, 0, 0);
}

double simulate_openmp(Particle *p, const SimParams *sp, int threads) {
    return simulate_core(p, sp, 1, threads);
}

void compute_metrics(const Particle *p, int n, double size, double cutoff, double *absmin, double *absavg) {
    // Approximate nearest-neighbor metrics using bins within 2*cutoff neighborhood
    Bins b; bins_init(&b, size, cutoff, n);
    bins_build(&b, p, n, size);
    double min_d = 1e9;
    double avg_sum = 0.0;
    for (int i = 0; i < n; i++) {
        int bi = bin_index(&b, p[i].x, p[i].y, size);
        int bix = bi % b.G;
        int biy = bi / b.G;
        double nn = 1e9;
        for (int dy = -2; dy <= 2; dy++) {
            for (int dx = -2; dx <= 2; dx++) {
                int nx = bix + dx;
                int ny = biy + dy;
                if (nx < 0 || ny < 0 || nx >= b.G || ny >= b.G) continue;
                int nbi = ny * b.G + nx;
                int start = b.offsets[nbi];
                int count = (nbi + 1 < b.G*b.G) ? (b.offsets[nbi+1] - start) : (n - start);
                for (int k = 0; k < count; k++) {
                    int j = b.indices[start + k];
                    if (j == i) continue;
                    double dxp = p[j].x - p[i].x;
                    double dyp = p[j].y - p[i].y;
                    double r = sqrt(dxp*dxp + dyp*dyp);
                    if (r < nn) nn = r;
                    if (r < min_d) min_d = r;
                }
            }
        }
        if (nn < 1e8) avg_sum += nn;
    }
    bins_free(&b);
    if (n > 0) {
        *absmin = min_d / cutoff;
        *absavg = (avg_sum / n) / cutoff;
    } else {
        *absmin = 0.0; *absavg = 0.0;
    }
}
