#include <mpi.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include "physics.h"

typedef struct { int rank, procs; double x0, x1; } Domain;

static void domain_setup(Domain *d, double size) {
    int rank, procs; MPI_Comm_rank(MPI_COMM_WORLD, &rank); MPI_Comm_size(MPI_COMM_WORLD, &procs);
    d->rank = rank; d->procs = procs;
    double w = size / procs;
    d->x0 = w * rank; d->x1 = w * (rank + 1);
}

static int owner_rank(double x, double size, int procs) {
    int r = (int)floor((x / size) * procs);
    if (r < 0) r = 0; if (r >= procs) r = procs - 1;
    return r;
}

static void pack_particles(const Particle *p, int n, double xlo, double xhi, int *count, Particle **buf) {
    int c = 0;
    for (int i = 0; i < n; i++) if (p[i].x >= xlo && p[i].x <= xhi) c++;
    *buf = (Particle*)malloc((size_t)c * sizeof(Particle));
    int k = 0;
    for (int i = 0; i < n; i++) if (p[i].x >= xlo && p[i].x <= xhi) (*buf)[k++] = p[i];
    *count = c;
}

static void migrate_particles(Particle **p, int *n, double size, int procs) {
    int rank; MPI_Comm_rank(MPI_COMM_WORLD, &rank);
    int *send_counts = (int*)calloc(procs, sizeof(int));
    int *send_displs = (int*)calloc(procs, sizeof(int));
    int *recv_counts = (int*)calloc(procs, sizeof(int));
    int *recv_displs = (int*)calloc(procs, sizeof(int));
    Particle **per_target = (Particle**)calloc(procs, sizeof(Particle*));
    int *per_target_n = (int*)calloc(procs, sizeof(int));
    for (int i = 0; i < *n; i++) {
        int dest = owner_rank((*p)[i].x, size, procs);
        if (dest != rank) per_target_n[dest]++;
    }
    for (int dst = 0; dst < procs; dst++) {
        if (per_target_n[dst] > 0) per_target[dst] = (Particle*)malloc((size_t)per_target_n[dst] * sizeof(Particle));
    }
    int *cursor = (int*)calloc(procs, sizeof(int));
    int kept = 0;
    for (int i = 0; i < *n; i++) {
        int dest = owner_rank((*p)[i].x, size, procs);
        if (dest == rank) {
            (*p)[kept++] = (*p)[i];
        } else {
            int idx = cursor[dest]++;
            per_target[dest][idx] = (*p)[i];
        }
    }
    *n = kept;
    *p = (Particle*)realloc(*p, (size_t)(*n) * sizeof(Particle));
    for (int dst = 0; dst < procs; dst++) send_counts[dst] = per_target_n[dst];
    MPI_Alltoall(send_counts, 1, MPI_INT, recv_counts, 1, MPI_INT, MPI_COMM_WORLD);
    int send_total = 0, recv_total = 0;
    for (int i = 0; i < procs; i++) { send_displs[i] = send_total; send_total += send_counts[i]; }
    for (int i = 0; i < procs; i++) { recv_displs[i] = recv_total; recv_total += recv_counts[i]; }
    Particle *sendbuf = NULL;
    if (send_total > 0) sendbuf = (Particle*)malloc((size_t)send_total * sizeof(Particle));
    for (int dst = 0, off = 0; dst < procs; dst++) {
        for (int i = 0; i < per_target_n[dst]; i++) sendbuf[off++] = per_target[dst][i];
    }
    Particle *recvbuf = NULL;
    if (recv_total > 0) recvbuf = (Particle*)malloc((size_t)recv_total * sizeof(Particle));
    // Convert counts/displs to bytes for MPI_BYTE
    int *send_counts_b = (int*)malloc((size_t)procs * sizeof(int));
    int *send_displs_b = (int*)malloc((size_t)procs * sizeof(int));
    int *recv_counts_b = (int*)malloc((size_t)procs * sizeof(int));
    int *recv_displs_b = (int*)malloc((size_t)procs * sizeof(int));
    for (int i = 0; i < procs; i++) {
        send_counts_b[i] = send_counts[i] * (int)sizeof(Particle);
        send_displs_b[i] = send_displs[i] * (int)sizeof(Particle);
        recv_counts_b[i] = recv_counts[i] * (int)sizeof(Particle);
        recv_displs_b[i] = recv_displs[i] * (int)sizeof(Particle);
    }
    MPI_Alltoallv(sendbuf, send_counts_b, send_displs_b, MPI_BYTE,
                  recvbuf, recv_counts_b, recv_displs_b, MPI_BYTE, MPI_COMM_WORLD);
    if (recv_total > 0) {
        *p = (Particle*)realloc(*p, (size_t)(*n + recv_total) * sizeof(Particle));
        memcpy((*p) + *n, recvbuf, (size_t)recv_total * sizeof(Particle));
        *n += recv_total;
    }
    for (int dst = 0; dst < procs; dst++) free(per_target[dst]);
    free(per_target); free(per_target_n); free(cursor);
    free(send_counts); free(send_displs); free(recv_counts); free(recv_displs);
    free(send_counts_b); free(send_displs_b); free(recv_counts_b); free(recv_displs_b);
    free(sendbuf); free(recvbuf);
}

static void exchange_ghosts(const Particle *p, int n, const Domain *d, double cutoff,
                            Particle **left_ghost, int *nl, Particle **right_ghost, int *nr) {
    int left_rank = d->rank - 1;
    int right_rank = d->rank + 1;
    Particle *send_left = NULL, *send_right = NULL; int sl = 0, sr = 0;
    double xlo = d->x0; double xhi = d->x1;
    double left_hi = xlo + cutoff;
    double right_lo = xhi - cutoff;
    if (left_rank >= 0) pack_particles(p, n, xlo, left_hi, &sl, &send_left);
    if (right_rank < d->procs) pack_particles(p, n, right_lo, xhi, &sr, &send_right);
    int recv_left = 0, recv_right = 0; MPI_Status st;
    if (left_rank >= 0) MPI_Sendrecv(&sr, 1, MPI_INT, left_rank, 0, &recv_left, 1, MPI_INT, left_rank, 0, MPI_COMM_WORLD, &st);
    if (right_rank < d->procs) MPI_Sendrecv(&sl, 1, MPI_INT, right_rank, 1, &recv_right, 1, MPI_INT, right_rank, 1, MPI_COMM_WORLD, &st);
    *left_ghost = recv_left > 0 ? (Particle*)malloc((size_t)recv_left * sizeof(Particle)) : NULL;
    *right_ghost = recv_right > 0 ? (Particle*)malloc((size_t)recv_right * sizeof(Particle)) : NULL;
    *nl = recv_left; *nr = recv_right;
    if (left_rank >= 0) {
        MPI_Sendrecv(send_right, sr * (int)sizeof(Particle), MPI_BYTE, left_rank, 2,
                     *left_ghost, recv_left * (int)sizeof(Particle), MPI_BYTE, left_rank, 2,
                     MPI_COMM_WORLD, &st);
    }
    if (right_rank < d->procs) {
        MPI_Sendrecv(send_left, sl * (int)sizeof(Particle), MPI_BYTE, right_rank, 3,
                     *right_ghost, recv_right * (int)sizeof(Particle), MPI_BYTE, right_rank, 3,
                     MPI_COMM_WORLD, &st);
    }
    free(send_left); free(send_right);
}

static void compute_forces_local(const Particle *local, int nloc, const Particle *gL, int nL, const Particle *gR, int nR,
                                 const SimParams *sp, double *fx, double *fy) {
    const double cutoff2 = sp->cutoff * sp->cutoff;
    const double k = 5.0; const double eps = 1e-12;
    for (int i = 0; i < nloc; i++) { fx[i] = 0.0; fy[i] = 0.0; }
    for (int i = 0; i < nloc; i++) {
        double fix = 0.0, fiy = 0.0;
        for (int j = 0; j < nloc; j++) if (j != i) {
            double dxp = local[j].x - local[i].x;
            double dyp = local[j].y - local[i].y;
            double r2 = dxp*dxp + dyp*dyp;
            if (r2 < cutoff2 && r2 > eps) {
                double r = sqrt(r2);
                double strength = k * (1.0 - (r / sp->cutoff));
                double invr = 1.0 / r;
                fix -= strength * dxp * invr; fiy -= strength * dyp * invr;
            }
        }
        for (int j = 0; j < nL; j++) {
            double dxp = gL[j].x - local[i].x;
            double dyp = gL[j].y - local[i].y;
            double r2 = dxp*dxp + dyp*dyp;
            if (r2 < cutoff2 && r2 > eps) {
                double r = sqrt(r2);
                double strength = k * (1.0 - (r / sp->cutoff));
                double invr = 1.0 / r;
                fix -= strength * dxp * invr; fiy -= strength * dyp * invr;
            }
        }
        for (int j = 0; j < nR; j++) {
            double dxp = gR[j].x - local[i].x;
            double dyp = gR[j].y - local[i].y;
            double r2 = dxp*dxp + dyp*dyp;
            if (r2 < cutoff2 && r2 > eps) {
                double r = sqrt(r2);
                double strength = k * (1.0 - (r / sp->cutoff));
                double invr = 1.0 / r;
                fix -= strength * dxp * invr; fiy -= strength * dyp * invr;
            }
        }
        fx[i] = fix; fy[i] = fiy;
    }
}

double simulate_mpi(Particle **global_out, int *n_global, const SimParams *sp, int *nloc_out) {
    Domain d; domain_setup(&d, sp->size);
    int rank = d.rank, procs = d.procs;
    Particle *local = NULL; int nloc = 0;
    if (rank == 0) {
        Particle *all = (Particle*)malloc((size_t)sp->n * sizeof(Particle));
        init_particles(all, sp->n, sp->size, sp->seed);
        int *counts = (int*)calloc(procs, sizeof(int));
        for (int i = 0; i < sp->n; i++) counts[owner_rank(all[i].x, sp->size, procs)]++;
        int *displs = (int*)calloc(procs, sizeof(int));
        int sum = 0; for (int r = 0; r < procs; r++) { displs[r] = sum; sum += counts[r]; }
        Particle *sorted = (Particle*)malloc((size_t)sp->n * sizeof(Particle));
        int *cursor = (int*)calloc(procs, sizeof(int));
        for (int i = 0; i < sp->n; i++) {
            int r = owner_rank(all[i].x, sp->size, procs);
            int pos = displs[r] + cursor[r]++;
            sorted[pos] = all[i];
        }
        nloc = counts[0];
        local = (Particle*)malloc((size_t)nloc * sizeof(Particle));
        memcpy(local, sorted + displs[0], (size_t)nloc * sizeof(Particle));
        for (int r = 1; r < procs; r++) {
            int cnt = counts[r];
            MPI_Send(&cnt, 1, MPI_INT, r, 10, MPI_COMM_WORLD);
            if (cnt > 0) MPI_Send(sorted + displs[r], cnt * (int)sizeof(Particle), MPI_BYTE, r, 11, MPI_COMM_WORLD);
        }
        free(all); free(counts); free(displs); free(sorted); free(cursor);
    } else {
        MPI_Status st; MPI_Recv(&nloc, 1, MPI_INT, 0, 10, MPI_COMM_WORLD, &st);
        local = (Particle*)malloc((size_t)nloc * sizeof(Particle));
        if (nloc > 0) MPI_Recv(local, nloc * (int)sizeof(Particle), MPI_BYTE, 0, 11, MPI_COMM_WORLD, &st);
    }
    double t0 = MPI_Wtime();
    double dt = sp->dt; double damp = sp->damping; double size = sp->size; double cutoff = sp->cutoff;
    for (int step = 0; step < sp->steps; step++) {
        Particle *gL = NULL, *gR = NULL; int nL = 0, nR = 0;
        exchange_ghosts(local, nloc, &d, cutoff, &gL, &nL, &gR, &nR);
        double *fx = (double*)malloc((size_t)nloc * sizeof(double));
        double *fy = (double*)malloc((size_t)nloc * sizeof(double));
        compute_forces_local(local, nloc, gL, nL, gR, nR, sp, fx, fy);
        for (int i = 0; i < nloc; i++) {
            local[i].vx = damp * (local[i].vx + dt * fx[i]);
            local[i].vy = damp * (local[i].vy + dt * fy[i]);
            local[i].x += dt * local[i].vx;
            local[i].y += dt * local[i].vy;
            if (local[i].y < 0) { local[i].y = -local[i].y; local[i].vy = -local[i].vy; }
            if (local[i].y > size) { local[i].y = 2*size - local[i].y; local[i].vy = -local[i].vy; }
            if (local[i].x < 0) { local[i].x = -local[i].x; local[i].vx = -local[i].vx; }
            if (local[i].x > size) { local[i].x = 2*size - local[i].x; local[i].vx = -local[i].vx; }
        }
        free(fx); free(fy); free(gL); free(gR);
        migrate_particles(&local, &nloc, size, procs);
    }
    double t1 = MPI_Wtime();
    int *counts = (int*)calloc(procs, sizeof(int));
    MPI_Allgather(&nloc, 1, MPI_INT, counts, 1, MPI_INT, MPI_COMM_WORLD);
    int *displs = (int*)calloc(procs, sizeof(int));
    int total = 0; for (int r = 0; r < procs; r++) { displs[r] = total; total += counts[r]; }
    Particle *all = NULL;
    if (rank == 0) all = (Particle*)malloc((size_t)total * sizeof(Particle));
    // Convert counts/displs to bytes for MPI_BYTE
    int *counts_b = (int*)malloc((size_t)procs * sizeof(int));
    int *displs_b = (int*)malloc((size_t)procs * sizeof(int));
    for (int i = 0; i < procs; i++) { counts_b[i] = counts[i] * (int)sizeof(Particle); displs_b[i] = displs[i] * (int)sizeof(Particle); }
    MPI_Gatherv(local, nloc * (int)sizeof(Particle), MPI_BYTE,
                all, counts_b, displs_b, MPI_BYTE, 0, MPI_COMM_WORLD);
    if (rank == 0) { *global_out = all; *n_global = total; } else { *global_out = NULL; *n_global = 0; }
    *nloc_out = nloc;
    free(local); free(counts); free(displs); free(counts_b); free(displs_b);
    return t1 - t0;
}
